/**
 * @summary Upload a document to the knowledge base
 */
export const getUploadKnowledgeUrl = () => {
  return `/api/knowledge`;
};

export const uploadKnowledge = async (
  uploadKnowledgeBody: UploadKnowledgeBody,
  options?: RequestInit,
): Promise<KnowledgeDocument> => {
  const formData = new FormData();
  if (uploadKnowledgeBody.file !== undefined) {
    formData.append(`file`, uploadKnowledgeBody.file);
  }
  if (uploadKnowledgeBody.businessId !== undefined) {
    formData.append(`businessId`, uploadKnowledgeBody.businessId);
  }
  if (uploadKnowledgeBody.title !== undefined) {
    formData.append(`title`, uploadKnowledgeBody.title);
  }

  return customFetch<KnowledgeDocument>(getUploadKnowledgeUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

